{"nbformat":4,"nbformat_minor":0,"metadata":{"colab":{"provenance":[],"authorship_tag":"ABX9TyOBx74hPu2+P7pRWo8TZRZC"},"kernelspec":{"name":"python3","display_name":"Python 3"},"language_info":{"name":"python"}},"cells":[{"cell_type":"code","execution_count":2,"metadata":{"id":"rmgTUKaikc7D","executionInfo":{"status":"ok","timestamp":1775521638016,"user_tz":240,"elapsed":515,"user":{"displayName":"Max Quan","userId":"14632126890561315285"}}},"outputs":[],"source":["from fastapi import FastAPI\n","import joblib\n","import numpy as np\n","\n","# --- Create the API application ---\n","app = FastAPI(title=\"Churn Prediction API\")\n","\n","# --- Load the saved model (from the .pkl file) ---\n","model = joblib.load(\"churn_model.pkl\")\n","\n","# --- Endpoint 1: Home page (just confirms the API is alive) ---\n","@app.get(\"/\")\n","def home():\n","    return {\"message\": \"Churn Prediction API is running\"}\n","\n","# --- Endpoint 2: Prediction (this is the one that does the work) ---\n","@app.post(\"/predict\")\n","def predict(data: dict):\n","    # Pull the customer's features out of the incoming request\n","    features = np.array([[\n","        data[\"int_rate\"],\n","        data[\"loan_amt\"],\n","        data[\"term_num\"]\n","    ]])\n","\n","    # Use the model to get a churn probability\n","    churn_prob = model.predict(features)[0][1]\n","\n","    return {\n","        \"Loan Prediction\": round(float(churn_prob), 4)\n","    }\n"]}]}